FROM shopping_list_items
WHERE id = #{id}

SELECT COUNT(*)
FROM shopping_list_items
WHERE household_id = #{householdId}

SELECT id, household_id, inventory_item_id, is_manual, purchased, purchased_quantity, added_at
FROM shopping_list_items
WHERE inventory_item_id = #{inventoryItemId} AND is_manual = #{isManual}

SELECT COUNT(*) > 0
FROM shopping_list_items
WHERE inventory_item_id = #{inventoryItemId}

